    std::string replacement = "<p>$1</p>";

    // Replace all instances of `[ ]` with the html formatted text
    html = std::regex_replace(markdown, pattern, replacement);

    return html;
}

int main() {
    // Define the markdown formatted text
    std::string markdown = "*Hello, **world**!*";

    // Call the markdown_to_html function to convert the markdown to html
    std::string html = markdown_to_html(markdown);

    // Print the html formatted text
    std::cout << html << std::endl;

    return 0;
}
```
