function isPrime(num) {
  // if num is less than 2, then it is not a prime number
  if (num < 2) {
    return false;
  }

  // if num is a multiple of 2, then it is not a prime number
  if (num % 2 === 0) {
    return false;
  }

  // if num is a multiple of 3, then it is not a prime number
  if (num % 3 === 0) {
