  }

  // if num is a multiple of 5, then it is not a prime number
  if (num % 5 === 0) {
    return false;
  }

  // if num is 7 or greater, then it is not a prime number
  if (num >= 7) {
    // if num is not divisible by any of the above numbers, then it is a prime number
    if (num % 2 === 0 && num % 3 === 0 && num % 5 === 0) {
